import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { FiCheck, FiClock, FiPackage, FiTruck, FiCheckCircle } from 'react-icons/fi';
import { useSocket } from '../../context/SocketContext';
import api from '../../services/api';

const OrderTracking = () => {
  const { orderNumber } = useParams();
  const [order, setOrder] = useState(null);
  const [loading, setLoading] = useState(true);
  const { socket, joinOrderRoom } = useSocket();

  useEffect(() => {
    fetchOrder();
  }, [orderNumber]);

  useEffect(() => {
    if (order && socket) {
      joinOrderRoom(order._id);
      socket.on('order-update', (data) => {
        if (data.orderId === order._id) {
          setOrder(prev => ({
            ...prev,
            status: data.status,
            statusHistory: [...prev.statusHistory, { status: data.status, timestamp: data.timestamp }]
          }));
        }
      });
      return () => socket.off('order-update');
    }
  }, [order, socket]);

  const fetchOrder = async () => {
    try {
      const res = await api.get(`/orders/my-orders?limit=100`);
      const foundOrder = res.data.orders.find(o => o.orderNumber === orderNumber);
      if (foundOrder) setOrder(foundOrder);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const getStatusStep = (status) => {
    const steps = ['pending', 'confirmed', 'preparing', 'ready', 'served'];
    return steps.indexOf(status);
  };

  const statusSteps = [
    { key: 'pending', label: 'Order Placed', icon: FiPackage },
    { key: 'confirmed', label: 'Confirmed', icon: FiCheck },
    { key: 'preparing', label: 'Preparing', icon: FiClock },
    { key: 'ready', label: 'Ready', icon: FiCheckCircle },
    { key: 'served', label: 'Served', icon: FiTruck }
  ];

  if (loading) {
    return (
      <div className="flex items-center justify-center h-96">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-primary-500"></div>
      </div>
    );
  }

  if (!order) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-16 text-center">
        <h2 className="text-2xl font-bold text-dark-800 mb-4">Order not found</h2>
        <Link to="/orders" className="btn-primary">View My Orders</Link>
      </div>
    );
  }

  const currentStep = getStatusStep(order.status);

  return (
    <div className="max-w-4xl mx-auto px-4 py-8">
      <div className="text-center mb-8">
        <h1 className="text-3xl font-bold text-dark-800">Track Order</h1>
        <p className="text-dark-500 mt-2">Order #{order.orderNumber}</p>
      </div>

      <div className="card p-8 mb-8">
        <div className="flex items-center justify-between mb-8">
          {statusSteps.map((step, index) => {
            const Icon = step.icon;
            const isCompleted = index <= currentStep;
            const isCurrent = index === currentStep;
            return (
              <React.Fragment key={step.key}>
                <div className="flex flex-col items-center">
                  <div className={`w-12 h-12 rounded-full flex items-center justify-center ${
                    isCompleted ? 'bg-primary-500 text-white' : 'bg-dark-200 text-dark-400'
                  } ${isCurrent ? 'ring-4 ring-primary-200' : ''}`}>
                    <Icon size={20} />
                  </div>
                  <span className={`text-xs mt-2 ${isCompleted ? 'text-primary-500 font-medium' : 'text-dark-400'}`}>
                    {step.label}
                  </span>
                </div>
                {index < statusSteps.length - 1 && (
                  <div className={`flex-1 h-1 mx-2 ${
                    index < currentStep ? 'bg-primary-500' : 'bg-dark-200'
                  }`} />
                )}
              </React.Fragment>
            );
          })}
        </div>

        {order.estimatedPreparationTime && (
          <div className="text-center p-4 bg-primary-50 rounded-lg">
            <p className="text-dark-600">Estimated preparation time</p>
            <p className="text-2xl font-bold text-primary-500">{order.estimatedPreparationTime} minutes</p>
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="card p-6">
          <h3 className="text-lg font-semibold mb-4">Order Details</h3>
          <div className="space-y-3">
            <div className="flex justify-between">
              <span className="text-dark-500">Order Type</span>
              <span className="font-medium capitalize">{order.orderType}</span>
            </div>
            {order.tableNumber && (
              <div className="flex justify-between">
                <span className="text-dark-500">Table</span>
                <span className="font-medium">{order.tableNumber}</span>
              </div>
            )}
            <div className="flex justify-between">
              <span className="text-dark-500">Payment</span>
              <span className="font-medium capitalize">{order.paymentMethod}</span>
            </div>
            <div className="flex justify-between">
              <span className="text-dark-500">Payment Status</span>
              <span className={`badge ${order.paymentStatus === 'completed' ? 'badge-success' : 'badge-warning'}`}>
                {order.paymentStatus}
              </span>
            </div>
          </div>
        </div>

        <div className="card p-6">
          <h3 className="text-lg font-semibold mb-4">Items</h3>
          <div className="space-y-2">
            {order.items.map((item, idx) => (
              <div key={idx} className="flex justify-between text-sm">
                <span className="text-dark-600">{item.name} x {item.quantity}</span>
                <span className="font-medium">₹{(item.price * item.quantity).toFixed(2)}</span>
              </div>
            ))}
            <hr />
            <div className="flex justify-between font-bold">
              <span>Total</span>
              <span>₹{order.totalAmount.toFixed(2)}</span>
            </div>
          </div>
        </div>
      </div>

      {order.statusHistory && order.statusHistory.length > 0 && (
        <div className="card p-6 mt-6">
          <h3 className="text-lg font-semibold mb-4">Status History</h3>
          <div className="space-y-3">
            {order.statusHistory.map((entry, idx) => (
              <div key={idx} className="flex items-center gap-3">
                <div className="w-3 h-3 rounded-full bg-primary-500"></div>
                <div>
                  <span className="font-medium capitalize">{entry.status}</span>
                  <span className="text-dark-400 text-sm ml-2">
                    {new Date(entry.timestamp).toLocaleString()}
                  </span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default OrderTracking;
